CREATE OR REPLACE TRIGGER TRG_INS_UPD_TGQPERGQUEST
BEFORE INSERT OR UPDATE ON TGQPERGQUEST
FOR EACH ROW
BEGIN
IF inserting THEN
:NEW.DTCRIACAO := SYSDATE;
END IF;

IF updating THEN
:NEW.DTALTER := SYSDATE;
END IF;
END;
/

CREATE OR REPLACE TRIGGER TRG_INS_UPD_TGQCAUSARAIZ
BEFORE INSERT OR UPDATE ON TGQCAUSARAIZ FOR EACH ROW
BEGIN
:NEW.DATAACAO := SYSDATE;
:NEW.CODUSU := STP_GET_CODUSULOGADO();
END
;/

/*
NomeObjeto: TRG_INS_UPD_TGQARQDOC
